using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // ── AddItem ──────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_NoException()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_NoException()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
        _cart.AddItem("SKU-002", 3, 4.50m);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_NoException()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
        _cart.AddItem("SKU-001", 2, 9.99m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_ZeroQuantity_ThrowsArgumentException()
    {
        _cart.AddItem("SKU-001", 0, 9.99m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NegativeQuantity_ThrowsArgumentException()
    {
        _cart.AddItem("SKU-001", -1, 9.99m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NegativePrice_ThrowsArgumentException()
    {
        _cart.AddItem("SKU-001", 1, -5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void AddItem_NullSku_ThrowsArgumentNullException()
    {
        _cart.AddItem(null!, 1, 9.99m);
    }

    // ── RemoveItem ───────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_NoException()
    {
        _cart.AddItem("SKU-001", 1, 9.99m);
        _cart.RemoveItem("SKU-001");
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        _cart.RemoveItem("SKU-MISSING");
    }

    [TestMethod]
    public void RemoveItem_AfterRemoval_ItemNotInTotal()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 1, 20.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    // ── CalculateTotal ───────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsPriceTimesQuantity()
    {
        _cart.AddItem("SKU-001", 3, 5.00m);

        Assert.AreEqual(15.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfLineItems()
    {
        _cart.AddItem("SKU-001", 2, 10.00m);
        _cart.AddItem("SKU-002", 1, 7.50m);

        Assert.AreEqual(27.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsRemainingItems()
    {
        _cart.AddItem("SKU-001", 1, 10.00m);
        _cart.AddItem("SKU-002", 2, 5.00m);
        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(10.00m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon ──────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() < 100.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        _cart.ApplyCoupon("BOGUS");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public void ApplyCoupon_NullCode_ThrowsArgumentNullException()
    {
        _cart.ApplyCoupon(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void ApplyCoupon_EmptyCart_ThrowsInvalidOperationException()
    {
        _cart.ApplyCoupon("SAVE10");
    }

    [TestMethod]
    public void ApplyCoupon_TotalNeverNegative()
    {
        _cart.AddItem("SKU-001", 1, 1.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() >= 0m);
    }
}

